    std::array<int, 64> data{};
    bool operator!=(const LargePayload& other) const = default;
};

struct SboStorageStatus {
    bool updateReportedChange;
    bool smallUsingSBO;
    std::size_t smallStackUsage;
    bool largeInitialized;
    bool largeUsingSBO;
};

SboStorageStatus test_sbo_storage_info(int initialSmall,
                                       int updatedSmall,
                                       int largeSeed) {
    // Create lambda function to generate large payload with seed
    auto createLargePayload = [seed = largeSeed]() {
        LargePayload payload;
        for (int i = 0; i < 64; ++i) {
            payload.data[i] = (seed + i) % 100;
        }
        return payload;
    };

    // Create small SBOResource with initial value
    reaction::memory::SBOResource<SmallPayload> smallResource{initialSmall};

    // Create large SBOResource with lambda-generated payload
    reaction::memory::SBOResource<LargePayload> largeResource{createLargePayload()};

    // Update small resource value and capture whether it reported a change
    bool updateChanged = smallResource.updateValue(updatedSmall);

    // Get storage information for both resources
    auto smallInfo = smallResource.getStorageInfo();
    auto largeInfo = largeResource.getStorageInfo();

    // Construct and return SBO storage status
    return SboStorageStatus{
        .updateReportedChange = updateChanged,
        .smallUsingSBO = smallInfo.using_sbo,
        .smallStackUsage = smallInfo.stack_usage,
        .largeInitialized = largeInfo.initialized,
        .largeUsingSBO = largeInfo.using_sbo
    };
}

